import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import './StudentDashboard.css';

export default function StudentDashboard() {
  const [complaints, setComplaints] = useState([]);
  const [form, setForm] = useState({ category: '', description: '', priority: 'medium' });
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [stats, setStats] = useState({ total: 0, pending: 0, inProgress: 0, resolved: 0 });
  
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    if (!token) {
      navigate('/login');
      return;
    }
    if (user?.role !== 'student') {
      setError('Access denied. Student only.');
      setTimeout(() => navigate('/login'), 2000);
      return;
    }
    fetchComplaints();
  }, []);

  const fetchComplaints = async () => {
    try {
      const res = await axios.get('/api/complaints/my', { 
        headers: { 'x-auth-token': token } 
      });
      setComplaints(res.data);
      
      const total = res.data.length;
      const pending = res.data.filter(c => c.status === 'pending').length;
      const inProgress = res.data.filter(c => c.status === 'in-progress').length;
      const resolved = res.data.filter(c => c.status === 'resolved').length;
      setStats({ total, pending, inProgress, resolved });
      
    } catch (err) {
      console.error('Error fetching complaints:', err);
      if (err.response?.status === 401) {
        localStorage.clear();
        navigate('/login');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (!form.category) {
      setError('Please select a category');
      return;
    }
    if (!form.description.trim()) {
      setError('Please enter a description');
      return;
    }

    setSubmitting(true);

    try {
      const response = await axios.post('/api/complaints', form, {
        headers: { 
          'x-auth-token': token,
          'Content-Type': 'application/json'
        }
      });
      
      console.log('Complaint submitted:', response.data);
      setSuccess('✅ Complaint submitted successfully!');
      setForm({ category: '', description: '', priority: 'medium' });
      fetchComplaints();
      
    } catch (err) {
      console.error('Submission error:', err.response || err);
      
      if (err.code === 'ERR_NETWORK') {
        setError('❌ Cannot connect to server. Backend may be down.');
      } else if (err.response?.status === 401) {
        setError('❌ Session expired. Please login again.');
        setTimeout(() => {
          localStorage.clear();
          navigate('/login');
        }, 2000);
      } else if (err.response?.status === 403) {
        setError('❌ Access denied. Student only.');
      } else {
        setError(err.response?.data?.message || '❌ Failed to submit complaint');
      }
    } finally {
      setSubmitting(false);
    }
  };

  const logout = () => { 
    localStorage.clear(); 
    navigate('/login'); 
  };

  const formatDate = d => new Date(d).toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'short',
    day: 'numeric'
  });

  // ============================================
  // COLOR FUNCTIONS FOR COMPLAINTS
  // ============================================
  
  // Get color based on complaint status
  const getStatusColor = (status) => {
    switch(status) {
      case 'pending': return '#f39c12'; // Orange
      case 'in-progress': return '#3498db'; // Blue
      case 'resolved': return '#27ae60'; // Green
      default: return '#7f8c8d'; // Gray
    }
  };

  // Get color based on priority
  const getPriorityColor = (priority) => {
    switch(priority) {
      case 'low': return '#27ae60'; // Green
      case 'medium': return '#f39c12'; // Orange
      case 'high': return '#e74c3c'; // Red
      default: return '#7f8c8d'; // Gray
    }
  };

  // ============================================
  // TEXT COLORS FOR CATEGORY AND DESCRIPTION
  // ============================================
  
  // Get color for category based on category type
  const getCategoryColor = (category) => {
    switch(category) {
      case 'plumbing': return '#2980b9'; // Dark Blue
      case 'electrical': return '#f1c40f'; // Yellow
      case 'carpentry': return '#8e44ad'; // Purple
      case 'cleaning': return '#16a085'; // Teal
      case 'other': return '#7f8c8d'; // Gray
      default: return '#2c3e50'; // Dark Gray
    }
  };

  // Get background color for category badge
  const getCategoryBadgeColor = (category) => {
    switch(category) {
      case 'plumbing': return '#e6f3ff'; // Light Blue
      case 'electrical': return '#fff9e6'; // Light Yellow
      case 'carpentry': return '#f3e5f5'; // Light Purple
      case 'cleaning': return '#e0f7fa'; // Light Teal
      case 'other': return '#f0f0f0'; // Light Gray
      default: return '#f0f0f0';
    }
  };

  // Get color for description text based on priority (or use a fixed color)
  const getDescriptionColor = (priority, status) => {
    // You can make description color dynamic based on priority
    if (priority === 'high') return '#c0392b'; // Dark Red for high priority descriptions
    if (status === 'resolved') return '#7f8c8d'; // Gray for resolved complaints
    return '#34495e'; // Default dark blue-gray
  };

  // Get icon based on category
  const getCategoryIcon = (category) => {
    switch(category) {
      case 'plumbing': return '🚰';
      case 'electrical': return '⚡';
      case 'carpentry': return '🪑';
      case 'cleaning': return '🧹';
      case 'other': return '📌';
      default: return '📝';
    }
  };

  // Get icon based on status
  const getStatusIcon = (status) => {
    switch(status) {
      case 'pending': return '⏳';
      case 'in-progress': return '🛠️';
      case 'resolved': return '✅';
      default: return '📝';
    }
  };

  if (loading) {
    return (
      <div className="student-loading">
        <div className="spinner"></div>
        <p>Loading your dashboard...</p>
      </div>
    );
  }

  return (
    <div className="student-dashboard">
      {/* Header */}
      <header className="student-header">
        <div className="header-content">
          <div className="logo">
            <h1>🏠 Hostel<span>Hub</span></h1>
            <p>Student Portal</p>
          </div>
          <div className="user-menu">
            <div className="user-avatar">
              {user?.name?.charAt(0) || 'S'}
            </div>
            <div className="user-info">
              <span className="user-name">{user?.name || 'Student'}</span>
              <span className="user-email">{user?.email || ''}</span>
            </div>
            <button onClick={logout} className="logout-btn">
              <span>🚪</span> Logout
            </button>
          </div>
        </div>
      </header>

      {/* Welcome Banner */}
      <div className="welcome-banner">
        <div className="banner-content">
          <h2>Welcome back, {user?.name?.split(' ')[0] || 'Student'}! 👋</h2>
          <p>Track and manage your hostel complaints from one place.</p>
        </div>
        <div className="quick-stats">
          <div className="stat-card">
            <span className="stat-value">{stats.total}</span>
            <span className="stat-label">Total</span>
          </div>
          <div className="stat-card pending">
            <span className="stat-value">{stats.pending}</span>
            <span className="stat-label">Pending</span>
          </div>
          <div className="stat-card progress">
            <span className="stat-value">{stats.inProgress}</span>
            <span className="stat-label">In Progress</span>
          </div>
          <div className="stat-card resolved">
            <span className="stat-value">{stats.resolved}</span>
            <span className="stat-label">Resolved</span>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="student-main">
        {/* Left Column - Complaint Form */}
        <div className="complaint-form-container">
          <div className="section-header">
            <h3>📝 Submit New Complaint</h3>
            <p>Fill in the details below to report an issue</p>
          </div>

          {error && <div className="error-message">{error}</div>}
          {success && <div className="success-message">{success}</div>}

          <form onSubmit={handleSubmit} className="complaint-form">
            <div className="form-group">
              <label>Category *</label>
              <select 
                name="category" 
                value={form.category} 
                onChange={handleChange} 
                required
                style={{ 
                  borderColor: form.category ? getCategoryColor(form.category) : '#e0e0e0',
                  color: form.category ? getCategoryColor(form.category) : '#333'
                }}
              >
                <option value="">Select a category</option>
                <option value="plumbing" style={{ color: '#2980b9' }}>🚰 Plumbing</option>
                <option value="electrical" style={{ color: '#f39c12' }}>⚡ Electrical</option>
                <option value="carpentry" style={{ color: '#8e44ad' }}>🪑 Carpentry</option>
                <option value="cleaning" style={{ color: '#16a085' }}>🧹 Cleaning</option>
                <option value="other" style={{ color: '#7f8c8d' }}>📌 Other</option>
              </select>
            </div>

            <div className="form-group">
              <label>Description *</label>
              <textarea 
                name="description" 
                value={form.description} 
                onChange={handleChange}
                placeholder="Describe the issue in detail..."
                rows="4"
                required
                style={{
                  borderColor: form.description ? '#27ae60' : '#e0e0e0'
                }}
              />
            </div>

            <div className="form-group">
              <label>Priority</label>
              <div className="priority-options">
                <label className={`priority-option ${form.priority === 'low' ? 'selected' : ''}`}>
                  <input
                    type="radio"
                    name="priority"
                    value="low"
                    checked={form.priority === 'low'}
                    onChange={handleChange}
                  />
                  <span className="priority-low" style={{ color: '#27ae60' }}>🟢 Low</span>
                </label>
                <label className={`priority-option ${form.priority === 'medium' ? 'selected' : ''}`}>
                  <input
                    type="radio"
                    name="priority"
                    value="medium"
                    checked={form.priority === 'medium'}
                    onChange={handleChange}
                  />
                  <span className="priority-medium" style={{ color: '#f39c12' }}>🟡 Medium</span>
                </label>
                <label className={`priority-option ${form.priority === 'high' ? 'selected' : ''}`}>
                  <input
                    type="radio"
                    name="priority"
                    value="high"
                    checked={form.priority === 'high'}
                    onChange={handleChange}
                  />
                  <span className="priority-high" style={{ color: '#e74c3c' }}>🔴 High</span>
                </label>
              </div>
            </div>

            <button 
              type="submit" 
              className="submit-btn" 
              disabled={submitting}
              style={{
                background: submitting ? '#95a5a6' : 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'
              }}
            >
              {submitting ? 'Submitting...' : 'Submit Complaint'}
            </button>
          </form>
        </div>

        {/* Right Column - Complaints List with COLOR-CODED TEXT */}
        <div className="complaints-list-container">
          <div className="section-header">
            <h3>📋 My Complaints</h3>
            <p>Track the status of your submitted complaints</p>
          </div>

          {complaints.length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">📭</div>
              <h4>No complaints yet</h4>
              <p>Submit your first complaint using the form</p>
            </div>
          ) : (
            <div className="complaints-timeline">
              {complaints.map((complaint, index) => {
                const categoryColor = getCategoryColor(complaint.category);
                const categoryBgColor = getCategoryBadgeColor(complaint.category);
                const descriptionColor = getDescriptionColor(complaint.priority, complaint.status);
                
                return (
                  <div 
                    key={complaint._id} 
                    className="timeline-item"
                    style={{
                      borderLeft: `4px solid ${getStatusColor(complaint.status)}`,
                      backgroundColor: '#ffffff',
                      borderRadius: '8px',
                      marginBottom: '15px',
                      padding: '15px',
                      boxShadow: '0 2px 5px rgba(0,0,0,0.1)'
                    }}
                  >
                    {/* Header with ID and Priority */}
                    <div className="complaint-header" style={{ 
                      display: 'flex', 
                      justifyContent: 'space-between', 
                      marginBottom: '12px' 
                    }}>
                      <span className="complaint-id" style={{ 
                        background: '#f0f0f0', 
                        padding: '4px 10px', 
                        borderRadius: '4px',
                        fontSize: '12px',
                        fontWeight: 'bold',
                        color: '#555'
                      }}>
                        #{complaint._id.slice(-6)}
                      </span>
                      <span 
                        className="priority-badge" 
                        style={{ 
                          backgroundColor: getPriorityColor(complaint.priority) + '20',
                          color: getPriorityColor(complaint.priority),
                          padding: '4px 12px',
                          borderRadius: '20px',
                          fontSize: '12px',
                          fontWeight: 'bold'
                        }}
                      >
                        {complaint.priority === 'low' && '🟢'}
                        {complaint.priority === 'medium' && '🟡'}
                        {complaint.priority === 'high' && '🔴'} {complaint.priority}
                      </span>
                    </div>
                    
                    {/* Category with COLOR and ICON */}
                    <div style={{ marginBottom: '10px' }}>
                      <span 
                        className="category-badge"
                        style={{ 
                          backgroundColor: categoryBgColor,
                          color: categoryColor,
                          padding: '5px 12px',
                          borderRadius: '20px',
                          fontSize: '14px',
                          fontWeight: 'bold',
                          display: 'inline-block'
                        }}
                      >
                        {getCategoryIcon(complaint.category)} {complaint.category}
                      </span>
                    </div>
                    
                    {/* Description with COLOR */}
                    <p 
                      className="complaint-description" 
                      style={{ 
                        color: grey,
                        fontSize: '15px',
                        lineHeight: '1.6',
                        marginBottom: '15px',
                        padding: '0 5px'
                      }}
                    >
                      {complaint.description}
                    </p>
                    
                    {/* Footer with Status and Date */}
                    <div className="complaint-footer" style={{ 
                      display: 'flex', 
                      justifyContent: 'space-between',
                      alignItems: 'center',
                      borderTop: '1px solid #f4ecec',
                      paddingTop: '12px',
                      marginTop: '5px'
                    }}>
                      <span 
                        className="status-badge" 
                        style={{ 
                          backgroundColor: getStatusColor(complaint.status) + '20',
                          color: getStatusColor(complaint.status),
                          padding: '5px 15px',
                          borderRadius: '20px',
                          fontSize: '13px',
                          fontWeight: 'bold'
                        }}
                      >
                        {getStatusIcon(complaint.status)} {complaint.status}
                      </span>
                      <span className="complaint-date" style={{ 
                        color: '#7f8c8d', 
                        fontSize: '13px',
                        fontWeight: '500'
                      }}>
                        📅 {formatDate(complaint.createdAt)}
                      </span>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* Color Legend */}
      <div style={{
        maxWidth: '1400px',
        margin: '20px auto',
        padding: '20px',
        background: 'white',
        borderRadius: '10px',
        boxShadow: '0 2px 10px rgba(0,0,0,0.05)'
      }}>
        <h4 style={{ marginBottom: '15px', color: '#333' }}>🎨 Color Legend</h4>
        <div style={{ display: 'flex', gap: '30px', flexWrap: 'wrap' }}>
          <div>
            <h5 style={{ marginBottom: '10px', color: '#555' }}>Categories</h5>
            <div style={{ display: 'flex', gap: '15px', flexWrap: 'wrap' }}>
              <span style={{ background: '#e6f3ff', color: '#2980b9', padding: '5px 10px', borderRadius: '5px' }}>🚰 Plumbing</span>
              <span style={{ background: '#fff9e6', color: '#f39c12', padding: '5px 10px', borderRadius: '5px' }}>⚡ Electrical</span>
              <span style={{ background: '#f3e5f5', color: '#8e44ad', padding: '5px 10px', borderRadius: '5px' }}>🪑 Carpentry</span>
              <span style={{ background: '#e0f7fa', color: '#16a085', padding: '5px 10px', borderRadius: '5px' }}>🧹 Cleaning</span>
              <span style={{ background: '#f0f0f0', color: '#7f8c8d', padding: '5px 10px', borderRadius: '5px' }}>📌 Other</span>
            </div>
          </div>
          <div>
            <h5 style={{ marginBottom: '10px', color: '#555' }}>Description Colors</h5>
            <div style={{ display: 'flex', gap: '15px', flexWrap: 'wrap' }}>
              <span style={{ color: '#c0392b', fontWeight: 'bold' }}>🔴 High Priority</span>
              <span style={{ color: '#34495e', fontWeight: 'bold' }}>⚫ Normal</span>
              <span style={{ color: '#7f8c8d', fontWeight: 'bold' }}>⚪ Resolved</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
